using System.Net.Http.Json;

namespace sv_bf3eb5883c724f179e8575d6d8f4df58.Client.Services;

/// <summary>
/// Client-side implementation that calls the server API over HTTP (used in WebAssembly).
/// </summary>
public sealed class ShipmentHttpClient(HttpClient http) : IShipmentService
{
    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var result = await http.GetFromJsonAsync<ShipmentDetails>(
            $"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        return result ?? throw new InvalidOperationException("Shipment not found.");
    }
}

