using sv_bf3eb5883c724f179e8575d6d8f4df58.Client.Services;

namespace sv_bf3eb5883c724f179e8575d6d8f4df58.Services;

/// <summary>
/// Server-side implementation that simulates a slow backend with fake data.
/// </summary>
public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails(
            "TRK-001",
            "In Transit",
            "Chicago, IL",
            new DateTimeOffset(2026, 5, 25, 14, 0, 0, TimeSpan.Zero),
            new List<StatusUpdate>
            {
                new("Package picked up", new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero)),
                new("Departed origin facility", new DateTimeOffset(2026, 5, 20, 15, 30, 0, TimeSpan.Zero)),
                new("Arrived at Chicago hub", new DateTimeOffset(2026, 5, 21, 6, 45, 0, TimeSpan.Zero)),
                new("In transit to destination", new DateTimeOffset(2026, 5, 22, 8, 0, 0, TimeSpan.Zero))
            }),

        ["TRK-002"] = new ShipmentDetails(
            "TRK-002",
            "Delivered",
            "Austin, TX",
            new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero),
            new List<StatusUpdate>
            {
                new("Package picked up", new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero)),
                new("In transit", new DateTimeOffset(2026, 5, 19, 7, 0, 0, TimeSpan.Zero)),
                new("Out for delivery", new DateTimeOffset(2026, 5, 21, 8, 30, 0, TimeSpan.Zero)),
                new("Delivered - signed by J. Smith", new DateTimeOffset(2026, 5, 21, 11, 15, 0, TimeSpan.Zero))
            }),

        ["TRK-003"] = new ShipmentDetails(
            "TRK-003",
            "Processing",
            "Seattle, WA",
            new DateTimeOffset(2026, 5, 28, 18, 0, 0, TimeSpan.Zero),
            new List<StatusUpdate>
            {
                new("Label created", new DateTimeOffset(2026, 5, 22, 14, 0, 0, TimeSpan.Zero))
            })
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"No shipment found for tracking number '{trackingNumber}'.");
    }
}

using sv_bf3eb5883c724f179e8575d6d8f4df58.Client.Services;

namespace sv_bf3eb5883c724f179e8575d6d8f4df58.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentApi(this WebApplication app)
    {
        app.MapGet("api/shipments/{trackingNumber}", async (
            string trackingNumber,
            IShipmentService service,
            CancellationToken ct) =>
        {
            try
            {
                var shipment = await service.GetShipmentAsync(trackingNumber, ct);
                return Results.Ok(shipment);
            }
            catch (KeyNotFoundException)
            {
                return Results.NotFound();
            }
        });
    }
}

